     1→import { useEffect } from 'react';
     2→import type { Renderer } from '@wc3-ui/core';
     3→import { useWC3Renderer } from '../context/WC3RendererContext';
     4→
     5→/**
     6→ * Registers an object with a renderer array on mount, removes it on unmount.
     7→ *
     8→ * @param registryKey - The key on Renderer that holds the registry array (e.g. 'checkboxes')
     9→ * @param buildReg - Factory called once on mount; returns the registration object.
    10→ *   The factory receives the renderer so it can access race textures etc. if needed.
    11→ *   The object is captured by reference — use `useRef`-backed callbacks inside it
    12→ *   so the renderer's RAF loop always reads the latest values without re-registering.
    13→ */
    14→export function useRendererRegistration<
    15→  K extends {
    16→    [P in keyof Renderer]: Renderer[P] extends unknown[] ? P : never;
    17→  }[keyof Renderer],
    18→>(
    19→  registryKey: K,
    20→  buildReg: (renderer: Renderer) => Renderer[K] extends (infer T)[] ? T : never,
    21→): void {
    22→  const renderer = useWC3Renderer();
    23→
    24→  useEffect(() => {
    25→    const reg = buildReg(renderer);
    26→    const arr = renderer[registryKey] as unknown[];
    27→    arr.push(reg);
    28→
    29→    return () => {
    30→      const idx = arr.indexOf(reg);
    31→      if (idx !== -1) arr.splice(idx, 1);
    32→    };
    33→    // buildReg is intentionally excluded — it should be a stable factory (use useCallback if needed)
    34→    // eslint-disable-next-line react-hooks/exhaustive-deps
    35→  }, [renderer, registryKey]);
    36→}
